112	async function doSync(): Promise<void> {
113	  let tokens: { idToken: string; accessToken: string; email?: string };
114	  try {
115	    tokens = await getValidTokens();
116	  } catch {
117	    // Token unavailable. If the user was connected, this is a recoverable lapse
118	    // (storage.session wiped on restart, or silent renew failed) — surface it so
119	    // nudging never dies silently. If they never connected, stay quiet.
120	    if (await wasConnected()) await setLapsed(true);
121	    return;
122	  }
123	  let result;
124	  try {
125	    result = await runSync(tokens.accessToken, domainOf(tokens.email));
126	  } catch (err) {
127	    console.warn('[auxilio] sync failed', err);
128	    return;
129	  }
130	
131	  // Got here with working tokens → any prior lapse is over.
132	  await setLapsed(false);
133	
134	  // Cross-channel suppression: ask the engine which marked events already have an
135	  // active pass (issued via the add-on or another device), so we don't nag for
136	  // them. Gated/throttled so this isn't a per-minute engine call.
137	  const engineHandled = await maybePollEngineStatus(tokens.idToken);
138	
139	  // Toolbar badge = distinct visitor events still needing passes (engine-filtered,
140	  // series-collapsed) — sourced from listMarked so it matches the banner exactly.
141	  const targets = await listMarked();
142	  await chrome.action.setBadgeBackgroundColor({ color: BADGE_COLOR });
143	  await chrome.action.setBadgeText({ text: targets.length > 0 ? String(targets.length) : '' });
144	
145	  // OS notification for each newly-discovered visitor event (out-of-tab alert) —
146	  // but never for one the engine has already handled elsewhere.
147	  for (const ev of result.newMarked) {
148	    if (!engineHandled.has((ev.iCalUid ?? '').toLowerCase())) notifyVisitorEvent(ev);
149	  }
150	
151	  // In-page nudge banner: push the current marked set to calendar tabs, plus
152	  // any events that just stopped being pending (deleted/cancelled) so the page
153	  // can purge stale optimistic nudges for them. Soft suggestions ride along on
154	  // the same broadcast (in-page only — never badged or notified).
155	  broadcastNudge(targets, result.cancelledIds, await listSuggested());
156	
157	  // If the event the panel is showing changed (post-save), tell it to refetch.
158	  const stored = await chrome.storage.session.get(ACTIVE_EID_KEY);
159	  const activeEid = stored[ACTIVE_EID_KEY] as string | undefined;
160	  if (activeEid) {
161	    const dec = decodeEid(activeEid);
