450	        try {
451	          await runSync(t.accessToken, domainOf(t.email)); // refresh before listing
452	        } catch (err) {
453	          console.warn('[auxilio] LIST_VISITOR_EVENTS refresh failed; serving cached set', err);
454	        }
455	        // Homescreen is a management surface: list pending AND already-sent events
456	        // (tagged status) — unlike the nag surfaces, which use listMarked.
457	        return listForPanel();
458	      });
459	
460	    case 'GET_NUDGE_TARGETS':
461	      // Cheap read of the last-synced marked set (no token / no sync) — lets the
462	      // content script seed its banner immediately on page load.
463	      return ok(await listMarked());
464	
465	    case 'GET_SUGGESTED_TARGETS':
466	      // Cheap read of the last-synced soft suggestion set, for the gentle nudge.
467	      return ok(await listSuggested());
468	
469	    case 'EVENT_STATE':
470	      // Pure local read (no token/network) so the injected row can resolve its
471	      // copy instantly: 'sent' | 'pending' | 'plain'.
472	      return ok({ state: await eventState(msg.eventId) });
473	
474	    case 'IS_EVENT_HANDLED':
475	      // Lets the in-page optimistic nudge skip an event whose passes were already
476	      // sent from this extension (the sync filters these, the optimistic path can't).
477	      return ok({ handled: await isEventHandled(msg.eventId) });
478	
479	    case 'IS_NUDGE_WORTHY':
480	      // The in-page OPTIMISTIC nudge (the instant, DOM-derived guess) exists ONLY to
481	      // bridge sync lag for a brand-new event. So suppress it for anything the sync
482	      // already knows about:
483	      //  - isEventHandled → passes were already sent from this extension; and
484	      //  - isEventMarked  → the event is already in the marked set, i.e. a pending
485	      //    event the sync banner already covers (and whose dismissal the content
486	      //    script remembers) OR an already-handled one.
487	      // This is what stops an already-sent / already-dismissed event from nudging
488	      // again when it's reopened and closed after a page refresh. Only a genuinely
489	      // new event (in neither set) reaches the organizer check below.
490	      return withTokens(async (t) => {
491	        if (await isEventHandled(msg.eventId)) return { worthy: false };
492	        if (await isEventMarked(msg.eventId)) return { worthy: false };
