1	/**
2	 * Calendar sync (background only). The durable, official "what changed" engine:
3	 * runs on a chrome.alarm, lists changes via a sync token, and maintains the set
4	 * of upcoming visitor (magic-address) events in storage.local. Drives:
5	 *  - post-save refresh of the open event (changedIds),
6	 *  - the visitor-event notification + toolbar badge (newMarked / count),
7	 *  - the side panel's "open from list" picker (listMarked).
8	 * No DOM. Reflects SAVED state only (pre-save edits are add-on-only — see
9	 * Planning-docs/2026-06-19_calendar_addon_vs_extension_capabilities.md).
10	 */
11	import { MAGIC_ADDRESS } from './config';
12	import { encodeEid, isMarked, isSuggested, listEvents } from './calendar';
13	import type { EventState, PanelVisitorEvent, VisitorEventSummary } from './types';
14	
15	const SYNC_TOKEN_KEY = 'auxilio.syncToken';
16	const MARKED_KEY = 'auxilio.markedEvents';
17	/** Events the user has already issued passes for from this extension — keyed by
18	 *  eventId, value = when handled. A durable overlay over the marked set so a
19	 *  finished event stops badging/notifying/nudging instead of nagging until it
20	 *  ages out. Local-only signal: passes sent via the add-on or another device
21	 *  won't appear here (full cross-channel truth needs an engine status endpoint —
22	 *  deferred). Pruned by HANDLED_TTL_MS. */
23	const HANDLED_KEY = 'auxilio.handledEvents';
24	/** iCalUids the ENGINE reports already have an active pass — i.e. handled through
25	 *  ANY surface (add-on, another device), not just this extension. Overwritten on
26	 *  each status poll (NOT durable like HANDLED_KEY): if passes are later cancelled
27	 *  elsewhere, the next poll drops the uid and the event correctly resurfaces. */
28	const ENGINE_HANDLED_KEY = 'auxilio.engineHandled';
29	/** Soft SUGGESTION set: organizer events that look visitor-bound (location/room +
30	 *  external guest) but have NO magic address yet. Drives only the gentle in-page
31	 *  nudge — never the badge or an OS notification. Rebuilt like the marked set. */
32	const SUGGESTED_KEY = 'auxilio.suggestedEvents';
33	/** When the last FULL (tokenless) re-scan ran. Incremental sync only reports
34	 *  changes, so an event missed when its change was first consumed (e.g. a
35	 *  different magic address in an earlier build) is never re-examined until a full
36	 *  re-scan. We force one periodically + on install so the set self-heals. */
37	const LAST_FULL_KEY = 'auxilio.lastFullSync';
38	/** Signature of the sync-relevant config (magic address + query schema) at the
39	 *  last run, so a plain reload can resume incremental sync instead of paying the
40	 *  full forward-window scan every time. See syncConfigChanged. */
41	const CONFIG_SIG_KEY = 'auxilio.configSig';
42	/** Bump when the events.list query SHAPE changes (e.g. adding timeMax) so the next
43	 *  load does one clean full re-scan to rebuild the marked set under the new query.
44	 *  v2 = bounded forward window (timeMax). v3 = organizer-only gate — forces a clean
45	 *  re-scan that drops events the user is merely a GUEST of, which earlier builds
46	 *  wrongly marked + nudged. v4 = adds the soft "suggested" set (location/room +
47	 *  external guest); a full re-scan populates it for events already in the window. */
48	const SYNC_SCHEMA_VERSION = 4;
49	const PAST_GRACE_MS = 60 * 60_000; // keep events until 1h after they end
50	const HANDLED_TTL_MS = 30 * 24 * 60 * 60_000; // forget "handled" after 30 days
51	const FULL_RESYNC_INTERVAL_MS = 12 * 60 * 60_000; // re-scan the whole window twice a day
52	
53	type MarkedMap = Record<string, VisitorEventSummary>;
54	type HandledMap = Record<string, number>;
55	
56	async function readMarked(): Promise<MarkedMap> {
57	  const r = await chrome.storage.local.get(MARKED_KEY);
58	  return (r[MARKED_KEY] as MarkedMap) ?? {};
59	}
60	
61	async function readHandled(): Promise<HandledMap> {
62	  const r = await chrome.storage.local.get(HANDLED_KEY);
63	  return (r[HANDLED_KEY] as HandledMap) ?? {};
64	}
65	
66	async function readSuggested(): Promise<MarkedMap> {
67	  const r = await chrome.storage.local.get(SUGGESTED_KEY);
68	  return (r[SUGGESTED_KEY] as MarkedMap) ?? {};
69	}
70	
71	/** The pass-linkage state of an event, for the injected row's dynamic copy. Pure
72	 *  local read (no network) so the row can resolve instantly:
73	 *   - 'sent'    = passes issued from this extension OR active via another surface;
74	 *   - 'pending' = a magic-address visitor event with no passes yet;
75	 *   - 'plain'   = anything else (ordinary or brand-new event).
76	 *  `eventId` is the plain Calendar event id (not the base64 eid). */
77	export async function eventState(eventId: string): Promise<EventState> {
78	  if (!eventId) return 'plain';
79	  const [marked, handled, engineHandled] = await Promise.all([
80	    readMarked(),
81	    readHandled(),
82	    readEngineHandled(),
83	  ]);
84	  const m = marked[eventId];
85	  const sent =
86	    !!handled[eventId] || (!!m && engineHandled.has((m.iCalUid ?? '').toLowerCase()));
87	  if (sent) return 'sent';
88	  if (m) return 'pending';
89	  return 'plain';
90	}
91	
92	/** Drop the sync token so the next sync does a full tokenless re-scan of the
93	 *  forward window. Called on a real config change so it takes effect immediately
94	 *  instead of waiting for the periodic resync. */
95	export async function clearSyncToken(): Promise<void> {
96	  await chrome.storage.local.remove([SYNC_TOKEN_KEY, LAST_FULL_KEY]);
97	}
98	
99	/** Did the sync-relevant config (magic address or query schema) change since the
100	 *  last run? That's the ONLY time we must drop the token for a full re-scan. A
101	 *  plain reload leaves the signature unchanged, so it keeps the token and resumes
102	 *  cheap incremental sync — instead of re-running the multi-second full scan (which
103	 *  the MV3 worker can be killed in the middle of) on every reload. Records the new
104	 *  signature as a side effect. The 12h periodic full re-scan still self-heals drift. */
105	export async function syncConfigChanged(): Promise<boolean> {
106	  const sig = `${MAGIC_ADDRESS}|v${SYNC_SCHEMA_VERSION}`;
107	  const r = await chrome.storage.local.get(CONFIG_SIG_KEY);
108	  if (r[CONFIG_SIG_KEY] === sig) return false;
109	  await chrome.storage.local.set({ [CONFIG_SIG_KEY]: sig });
110	  return true;
111	}
112	
113	/** Record that passes were issued for this event — drops it from every nudge
114	 *  surface (badge, banner, notification, picker) until it ages out. */
115	export async function markHandled(eventId: string): Promise<void> {
116	  if (!eventId) return;
117	  const handled = await readHandled();
118	  handled[eventId] = Date.now();
119	  await chrome.storage.local.set({ [HANDLED_KEY]: handled });
120	}
121	
122	/** Forget that an event was handled — so its injected row reverts from "Manage
123	 *  visitors" to the create/send copy after its passes are all cancelled. */
124	export async function markUnhandled(eventId: string): Promise<void> {
125	  if (!eventId) return;
126	  const handled = await readHandled();
127	  if (!(eventId in handled)) return;
128	  delete handled[eventId];
129	  await chrome.storage.local.set({ [HANDLED_KEY]: handled });
130	}
131	
132	export async function readEngineHandled(): Promise<Set<string>> {
133	  const r = await chrome.storage.local.get(ENGINE_HANDLED_KEY);
134	  return new Set((r[ENGINE_HANDLED_KEY] as string[]) ?? []);
135	}
136	
137	/** Has this event already been handled (passes issued) from THIS extension? Reads
138	 *  the local handled overlay — lets the in-page optimistic nudge skip an event the
139	 *  user already sent passes for, instead of re-nudging when they reopen/close it
140	 *  (the sync set already filters handled events, but the optimistic DOM guess
141	 *  bypasses that filter). engineHandled isn't consulted here: it's keyed by iCalUid,
142	 *  which the optimistic path doesn't have. */
143	export async function isEventHandled(eventId: string): Promise<boolean> {
144	  if (!eventId) return false;
145	  const handled = await readHandled();
146	  return !!handled[eventId];
147	}
148	
149	/** iCalUids of marked events that aren't LOCALLY handled — the candidate set to
150	 *  ask the engine about. Deliberately ignores engineHandled: we must keep asking
151	 *  about already-engine-handled events so a pass cancelled elsewhere is re-detected
152	 *  and the event resurfaces. */
153	export async function listPendingICalUids(): Promise<string[]> {
154	  const [marked, handled] = await Promise.all([readMarked(), readHandled()]);
155	  const uids = new Set<string>();
156	  for (const m of Object.values(marked)) {
157	    if (handled[m.eventId]) continue;
158	    if (m.iCalUid) uids.add(m.iCalUid);
159	  }
160	  return [...uids];
161	}
162	
163	/** Replace the engine-handled iCalUid set with the latest status answer. Overwrite
164	 *  (not merge) so events whose passes were cancelled elsewhere drop out and
165	 *  resurface. Lower-cased for case-insensitive matching against marked iCalUids. */
166	export async function setEngineHandled(iCalUids: string[]): Promise<void> {
167	  await chrome.storage.local.set({
168	    [ENGINE_HANDLED_KEY]: [...new Set(iCalUids.map((u) => u.toLowerCase()))],
169	  });
170	}
171	
172	export interface SyncResult {
173	  changedIds: Set<string>;
174	  newMarked: VisitorEventSummary[];
175	  /** Events seen this cycle that are no longer pending visitor events (deleted/
176	   *  cancelled). Lets the in-page nudge purge stale optimistic guesses. */
177	  cancelledIds: string[];
178	  /** Tracked visitor events DELETED this cycle (Google status 'cancelled'), with the
179	   *  iCalUid we held for them. Drives the orphan-pass safety net: the background asks
180	   *  the engine to revoke their passes, covering the case where the host's server-side
181	   *  calendar watch isn't connected and would never learn of the deletion. */
182	  cancelledWithUid: { eventId: string; iCalUid: string }[];
183	  markedCount: number;
184	}
185	
186	/** Coalesce concurrent syncs (the 1-minute alarm + on-demand LIST/SYNC_NOW) so
187	 *  they can't race on the shared sync token / marked map and lose an update — both
188	 *  read the same baseline, both write at the end, and the later write clobbers the
189	 *  earlier one (an event one run marked can vanish, and won't be re-reported once
190	 *  the token advances). One in-flight sync at a time removes that hazard. */
191	let inFlight: Promise<SyncResult> | null = null;
192	export function runSync(accessToken: string, selfDomain?: string): Promise<SyncResult> {
193	  if (inFlight) return inFlight;
194	  inFlight = doRunSync(accessToken, selfDomain).finally(() => {
195	    inFlight = null;
196	  });
197	  return inFlight;
198	}
199	
200	/** Pull changes since the last sync; update the marked set; report deltas.
201	 *  `selfDomain` (the signed-in user's email domain) gates the soft "suggested"
202	 *  set — without it we suggest nothing (can't tell internal from external). */
203	async function doRunSync(accessToken: string, selfDomain = ''): Promise<SyncResult> {
204	  const store = await chrome.storage.local.get([
205	    SYNC_TOKEN_KEY,
206	    MARKED_KEY,
207	    HANDLED_KEY,
208	    ENGINE_HANDLED_KEY,
209	    SUGGESTED_KEY,
210	    LAST_FULL_KEY,
211	  ]);
212	  const engineHandled = new Set((store[ENGINE_HANDLED_KEY] as string[]) ?? []);
213	  // The set we knew BEFORE this sync — the baseline for "what's genuinely new"
214	  // (so a full re-scan that re-discovers the whole window doesn't re-notify).
215	  const prevMarked = (store[MARKED_KEY] as MarkedMap) ?? {};
216	  const prevSuggested = (store[SUGGESTED_KEY] as MarkedMap) ?? {};
217	  const handled = (store[HANDLED_KEY] as HandledMap) ?? {};
218	  const lastFull = (store[LAST_FULL_KEY] as number) ?? 0;
219	
220	  let syncToken = store[SYNC_TOKEN_KEY] as string | undefined;
221	  // Force a periodic full re-scan: incremental sync never re-reports an event
222	  // whose change was already consumed, so a once-missed event (wrong magic
223	  // address in a past build, a transient attendee trim) would stay invisible
224	  // forever. Dropping the token re-evaluates the whole forward window.
225	  if (syncToken && Date.now() - lastFull > FULL_RESYNC_INTERVAL_MS) {
226	    syncToken = undefined;
227	  }
228	
229	  let resp = await listEvents(accessToken, { syncToken });
230	  if (resp.expired) {
231	    // Token stale → full resync from scratch.
232	    syncToken = undefined;
233	    resp = await listEvents(accessToken, {});
234	  }
235	  // A tokenless call re-scanned the full window; rebuild the set from scratch so
236	  // stale/no-longer-marked events drop out. Incremental carries the set forward.
237	  const fullSync = !syncToken;
238	  const marked: MarkedMap = fullSync ? {} : { ...prevMarked };
239	  // Soft suggestion set, carried forward incrementally like `marked`.
240	  const suggested: MarkedMap = fullSync ? {} : { ...prevSuggested };
241	
242	  const changedIds = new Set<string>();
243	  const newMarked: VisitorEventSummary[] = [];
244	  const cancelledIds: string[] = [];
245	  const cancelledWithUid: { eventId: string; iCalUid: string }[] = [];
246	
247	  // Series we already tracked (any previously-marked instance) — so a newly
248	  // discovered later occurrence of a known recurring event, OR a full re-scan
249	  // that re-finds the whole window, doesn't fire a fresh notification.
250	  const knownSeries = new Set(
251	    Object.values(prevMarked).map((m) => m.seriesId ?? m.eventId),
252	  );
253	  // Series notified within THIS cycle — collapses an initial sync that discovers
254	  // dozens of weekly instances at once down to a single notification.
255	  const notifiedSeries = new Set<string>();
256	
257	  for (const ev of resp.items) {
258	    if (!ev.id) continue;
259	    changedIds.add(ev.id);
260	    const cancelled = ev.status === 'cancelled';
261	    const hasMagic = isMarked(ev);
262	    // DIAGNOSTIC: the magic address is somewhere in this event's payload, yet
263	    // isMarked() didn't flag it — i.e. it's not a structured attendee email and
264	    // not in `location` (e.g. it's only in the description, or events.list
265	    // returned a trimmed attendee list). This is the signature of a primary-
266	    // calendar miss; the warning shows exactly what we got back.
267	    if (!hasMagic && MAGIC_ADDRESS && JSON.stringify(ev).toLowerCase().includes(MAGIC_ADDRESS)) {
268	      console.warn(
269	        '[auxilio] sync MISS: magic address in payload but isMarked() is false',
270	        { id: ev.id, summary: ev.summary, location: ev.location, attendees: ev.attendees, status: ev.status },
271	      );
272	    }
273	    // Only the event's ORGANIZER (the host) registers visitors. A guest who was
274	    // merely invited to a visitor event sees the magic address among the attendees
275	    // on THEIR copy too — but they must never be nudged/badged/notified to "manage"
276	    // someone else's event (the reported bug). organizer.self is Google's
277	    // authoritative "this calendar's user owns the event" flag.
278	    const marked_ = hasMagic && ev.organizer?.self === true;
279	    if (marked_ && !cancelled) {
280	      const seriesId = ev.recurringEventId || ev.id;
281	      const summary: VisitorEventSummary = {
282	        eid: encodeEid(ev.id, 'primary'),
283	        eventId: ev.id,
284	        iCalUid: ev.iCalUID ?? '',
285	        title: ev.summary || '(no title)',
286	        start: ev.start?.dateTime ?? ev.start?.date,
287	        seriesId,
288	      };
289	      // Notify only for a genuinely new, not-yet-handled occurrence of a series we
290	      // weren't already tracking — one alert per recurring series, not per
291	      // instance, and never for an event a full re-scan merely re-discovered.
292	      const newInstance = !prevMarked[ev.id] && !handled[ev.id];
293	      if (newInstance && !knownSeries.has(seriesId) && !notifiedSeries.has(seriesId)) {
294	        newMarked.push(summary);
295	        notifiedSeries.add(seriesId);
296	      }
297	      marked[ev.id] = summary;
298	    } else {
299	      // Cancelled (deleted) or no longer a tracked visitor event (magic removed, or
300	      // not organized by us) → not pending. Report it so any optimistic in-page nudge
301	      // for it gets purged, and drop it from the marked set.
302	      if (cancelled || prevMarked[ev.id]) cancelledIds.push(ev.id);
303	      // Orphan-pass safety net: a tracked visitor event GENUINELY DELETED on Google
304	      // (status 'cancelled') may still have live passes if the host's server-side
305	      // calendar watch isn't connected. Capture its iCalUid (from the set we held)
306	      // so the background can ask the engine to revoke them. iCalUid may be absent on
307	      // the cancelled payload itself, so prefer the value we already stored.
308	      if (cancelled) {
309	        const uid = prevMarked[ev.id]?.iCalUid || ev.iCalUID || '';
310	        if (uid) cancelledWithUid.push({ eventId: ev.id, iCalUid: uid });
311	      }
312	      delete marked[ev.id];
313	      // Only FORGET the "handled" record on a genuine cancel/delete. Don't drop it
314	      // just because the event left our tracked set for another reason (e.g. a
315	      // momentarily-absent organizer.self on one sync pass) — that would let an
316	      // already-sent event re-nudge through the optimistic path. The 30-day TTL
317	      // (handledCutoff below) prunes stale records anyway.
318	      if (cancelled) delete handled[ev.id];
319	    }
320	
321	    // Soft suggestion set (never notified/badged): a visitor-likely event the host
322	    // hasn't added the magic address to yet. Mutually exclusive with `marked` —
323	    // becoming a magic event (marked_), cancelled, or no longer qualifying drops it.
324	    if (!cancelled && !marked_ && ev.organizer?.self === true && isSuggested(ev, selfDomain)) {
325	      suggested[ev.id] = {
326	        eid: encodeEid(ev.id, 'primary'),
327	        eventId: ev.id,
328	        iCalUid: ev.iCalUID ?? '',
329	        title: ev.summary || '(no title)',
330	        start: ev.start?.dateTime ?? ev.start?.date,
331	        seriesId: ev.recurringEventId || ev.id,
332	      };
333	    } else {
334	      delete suggested[ev.id];
335	    }
336	  }
337	
338	  // Prune events that are well past.
339	  const cutoff = Date.now() - PAST_GRACE_MS;
340	  for (const id of Object.keys(marked)) {
341	    const s = marked[id].start;
342	    if (s && Date.parse(s) < cutoff) delete marked[id];
343	  }
344	  for (const id of Object.keys(suggested)) {
345	    const s = suggested[id].start;
346	    if (s && Date.parse(s) < cutoff) delete suggested[id];
347	  }
348	
349	  // Prune stale "handled" records so the overlay can't grow without bound.
350	  const handledCutoff = Date.now() - HANDLED_TTL_MS;
351	  for (const id of Object.keys(handled)) {
352	    if (handled[id] < handledCutoff) delete handled[id];
353	  }
354	
355	  // DIAGNOSTIC: one line per sync so a primary-calendar miss is obvious — did the
356	  // list even return the event (itemsReturned), and did anything end up marked?
357	  console.log('[auxilio] sync done', {
358	    mode: fullSync ? 'full' : 'incremental',
359	    magicAddress: MAGIC_ADDRESS,
360	    itemsReturned: resp.items.length,
361	    markedTotal: Object.keys(marked).length,
362	    newMarked: newMarked.length,
363	  });
364	
365	  await chrome.storage.local.set({
366	    [SYNC_TOKEN_KEY]: resp.nextSyncToken ?? syncToken,
367	    [MARKED_KEY]: marked,
368	    [SUGGESTED_KEY]: suggested,
369	    [HANDLED_KEY]: handled,
370	    // Stamp the full-resync clock only when we actually did one, so the periodic
371	    // re-scan fires on schedule regardless of how often incremental sync runs.
372	    ...(fullSync ? { [LAST_FULL_KEY]: Date.now() } : {}),
373	  });
374	
375	  // markedCount drives the toolbar badge — count distinct pending series (a
376	  // recurring event counts once, not once per occurrence), excluding events the
377	  // engine already handled elsewhere. Uses the engineHandled set from the start
378	  // of this sync; the post-sync status poll reconciles the badge if it changed.
379	  const pendingSeries = new Set<string>();
380	  for (const id of Object.keys(marked)) {
381	    if (handled[id]) continue;
382	    if (engineHandled.has((marked[id].iCalUid ?? '').toLowerCase())) continue;
383	    pendingSeries.add(marked[id].seriesId ?? id);
384	  }
385	  return { changedIds, newMarked, cancelledIds, cancelledWithUid, markedCount: pendingSeries.size };
386	}
387	
388	/** Upcoming visitor events still needing passes, soonest first — for the panel's
389	 *  picker and the in-page nudge. Handled events are filtered out, and a recurring
390	 *  series collapses to its soonest pending occurrence (one row, not one per week). */
391	export async function listMarked(): Promise<VisitorEventSummary[]> {
392	  const [marked, handled, engineHandled] = await Promise.all([
393	    readMarked(),
394	    readHandled(),
395	    readEngineHandled(),
396	  ]);
397	  const bySeries = new Map<string, VisitorEventSummary>();
398	  for (const m of Object.values(marked)) {
399	    if (handled[m.eventId]) continue;
400	    if (engineHandled.has((m.iCalUid ?? '').toLowerCase())) continue;
401	    const key = m.seriesId ?? m.eventId;
402	    const existing = bySeries.get(key);
403	    if (!existing || (m.start ?? '~').localeCompare(existing.start ?? '~') < 0) {
404	      bySeries.set(key, m);
405	    }
406	  }
407	  return [...bySeries.values()].sort((a, b) =>
408	    (a.start ?? '').localeCompare(b.start ?? ''),
409	  );
410	}
411	
412	/** Soft suggestions (location/room + external guest, no magic address yet) for the
413	 *  gentle in-page nudge only. Series-collapsed to the soonest occurrence; excludes
414	 *  anything that's become a firm magic event or already handled. */
415	export async function listSuggested(): Promise<VisitorEventSummary[]> {
416	  const [suggested, marked, handled] = await Promise.all([
417	    readSuggested(),
418	    readMarked(),
419	    readHandled(),
420	  ]);
421	  const bySeries = new Map<string, VisitorEventSummary>();
422	  for (const s of Object.values(suggested)) {
423	    if (marked[s.eventId] || handled[s.eventId]) continue; // promoted/handled → not a suggestion
424	    const key = s.seriesId ?? s.eventId;
425	    const existing = bySeries.get(key);
426	    if (!existing || (s.start ?? '~').localeCompare(existing.start ?? '~') < 0) {
427	      bySeries.set(key, s);
428	    }
429	  }
430	  return [...bySeries.values()].sort((a, b) =>
431	    (a.start ?? '').localeCompare(b.start ?? ''),
432	  );
433	}
434	
435	/** Every upcoming visitor event for the side-panel homescreen — the MANAGEMENT
436	 *  surface. Unlike listMarked (which feeds the nag surfaces and hides handled
437	 *  events), this INCLUDES sent events tagged `status:'sent'` so a host can reopen
438	 *  one to update or cancel, and so the screen confirms finished work instead of
439	 *  going barren after the last send. Series-collapsed to one row: a recurring
440	 *  series is 'pending' if ANY occurrence in the window still needs passes (shown at
441	 *  its soonest pending occurrence), otherwise 'sent' (shown at its soonest). */
442	export async function listForPanel(): Promise<PanelVisitorEvent[]> {
443	  const [marked, handled, engineHandled] = await Promise.all([
444	    readMarked(),
445	    readHandled(),
446	    readEngineHandled(),
447	  ]);
448	  const isSent = (m: VisitorEventSummary) =>
449	    !!handled[m.eventId] || engineHandled.has((m.iCalUid ?? '').toLowerCase());
450	  const earlier = (a: VisitorEventSummary, b?: VisitorEventSummary) =>
451	    !b || (a.start ?? '~').localeCompare(b.start ?? '~') < 0;
452	
453	  const bySeries = new Map<
454	    string,
455	    { soonestAny: VisitorEventSummary; soonestPending?: VisitorEventSummary }
456	  >();
457	  for (const m of Object.values(marked)) {
458	    const key = m.seriesId ?? m.eventId;
459	    const entry = bySeries.get(key) ?? { soonestAny: m };
460	    if (earlier(m, entry.soonestAny)) entry.soonestAny = m;
461	    if (!isSent(m) && earlier(m, entry.soonestPending)) entry.soonestPending = m;
462	    bySeries.set(key, entry);
463	  }
464	
465	  const rows: PanelVisitorEvent[] = [...bySeries.values()].map((e) =>
466	    e.soonestPending
467	      ? { ...e.soonestPending, status: 'pending' }
468	      : { ...e.soonestAny, status: 'sent' },
469	  );
470	  return rows.sort((a, b) => (a.start ?? '').localeCompare(b.start ?? ''));
471	}
472	
473	/** Is this event id currently a known visitor event? */
474	export async function isEventMarked(eventId: string): Promise<boolean> {
475	  const marked = await readMarked();
476	  return !!marked[eventId];
477	}
478

