1	/**
2	 * Auth (background only). Mints a Google id_token (engine auth) + access_token
3	 * (Calendar read) via chrome.identity.launchWebAuthFlow against a Web OAuth
4	 * client, caches them in storage.session, and silently re-mints on expiry.
5	 *
6	 * The id_token's audience must be on the engine's AUXILIO_WORKSPACE_OAUTH_CLIENT_ID
7	 * allow-list. Calendar-only scopes (no Gmail/Drive — CASA line).
8	 */
9	import { OAUTH_CLIENT_ID } from './config';
10	import { engine } from './engine';
11	import type { AuthStatus } from './types';
12	
13	const SCOPES = [
14	  'openid',
15	  'email',
16	  'profile',
17	  'https://www.googleapis.com/auth/calendar.events.readonly',
18	  // Resolve guest names + photos the Calendar event API omits for external guests
19	  // (People API, client-side — mirrors the add-on). Both are *sensitive* scopes,
20	  // NOT restricted → no CASA, and still no Gmail/Drive. Adding these requires each
21	  // user to re-consent once (a silent renew won't widen scope).
22	  'https://www.googleapis.com/auth/contacts.readonly',
23	  'https://www.googleapis.com/auth/contacts.other.readonly',
24	].join(' ');
25	
26	const KEY = 'auxilio.tokens';
27	
28	/** Durable (storage.local) marker that the user has connected and intends to stay
29	 *  connected. Token bundles live in storage.session and are WIPED on every browser
30	 *  restart, so an absent bundle can't tell "never signed in" from "session cleared,
31	 *  silent renew due." This flag survives restarts: while it's set, a failed silent
32	 *  renew means auth has lapsed (surface a reconnect), not that the user is signed
33	 *  out. Cleared only on explicit sign-out. */
34	const CONNECTED_KEY = 'auxilio.connected';
35	/** Durable copy of the connected account's email. storage.session (the token
36	 *  bundle) is wiped on browser restart, but a silent renew needs to know WHICH
37	 *  Google account to refresh — without a login_hint, prompt=none fails on a
38	 *  multi-account profile (Google can't pick one non-interactively), which surfaces
39	 *  as every write silently failing. Survives the restart so the hint is available. */
40	const EMAIL_KEY = 'auxilio.email';
41	
42	interface TokenBundle {
43	  idToken: string;
44	  accessToken: string;
45	  email?: string;
46	  expiresAt: number;
47	}
48	
49	function parseFragment(redirectUrl: string) {
50	  const params = new URLSearchParams(new URL(redirectUrl).hash.slice(1));
51	  return {
52	    accessToken: params.get('access_token') ?? '',
53	    idToken: params.get('id_token') ?? '',
54	    code: params.get('code') ?? '',
55	    expiresIn: Number(params.get('expires_in') ?? '3600'),
56	    error: params.get('error') ?? undefined,
57	  };
58	}
59	
60	function emailFromIdToken(idToken: string): string | undefined {
61	  try {
62	    const part = idToken.split('.')[1].replace(/-/g, '+').replace(/_/g, '/');
63	    return JSON.parse(atob(part)).email as string | undefined;
64	  } catch {
65	    return undefined;
66	  }
67	}
68	
69	async function readCache(): Promise<TokenBundle | null> {
70	  const r = await chrome.storage.session.get(KEY);
71	  return (r[KEY] as TokenBundle) ?? null;
72	}
73	
74	async function mint(
75	  interactive: boolean,
76	  loginHint?: string,
77	): Promise<{ bundle: TokenBundle; code?: string }> {
78	  if (!OAUTH_CLIENT_ID) {
79	    throw new Error(
80	      'OAuth client id missing. Set WXT_OAUTH_CLIENT_ID in .env and rebuild.',
81	    );
82	  }
83	  const url = new URL('https://accounts.google.com/o/oauth2/v2/auth');
84	  url.searchParams.set('client_id', OAUTH_CLIENT_ID);
85	  // Interactive: hybrid flow (+ offline) so we ALSO get a code to hand the engine
86	  // for a calendar refresh token. Silent renew stays implicit (client tokens only).
87	  url.searchParams.set('response_type', interactive ? 'code token id_token' : 'token id_token');
88	  url.searchParams.set('redirect_uri', chrome.identity.getRedirectURL());
89	  url.searchParams.set('scope', SCOPES);
90	  url.searchParams.set('nonce', crypto.randomUUID());
91	  url.searchParams.set('prompt', interactive ? 'consent select_account' : 'none');
92	  if (interactive) url.searchParams.set('access_type', 'offline');
93	  // Tell Google which account to (re)use. Essential for the silent prompt=none
94	  // renew on a multi-account profile — without it Google can't choose an account
95	  // non-interactively and the renew fails, dead-ending every authed request.
96	  if (loginHint) url.searchParams.set('login_hint', loginHint);
97	
98	  const redirect = await chrome.identity.launchWebAuthFlow({
99	    url: url.toString(),
100	    interactive,
101	  });
102	  if (!redirect) throw new Error('Sign-in was cancelled');
103	
104	  const { accessToken, idToken, code, expiresIn, error } = parseFragment(redirect);
105	  if (error) throw new Error(`Google sign-in error: ${error}`);
106	  if (!idToken || !accessToken) throw new Error('Sign-in did not return tokens');
107	
108	  const email = emailFromIdToken(idToken);
109	  const bundle: TokenBundle = {
110	    idToken,
111	    accessToken,
112	    email,
113	    expiresAt: Date.now() + (expiresIn - 60) * 1000, // refresh 60s early
114	  };
115	  await chrome.storage.session.set({ [KEY]: bundle });
116	  // Persist the email durably so a later silent renew (after a restart wipes the
117	  // session bundle) still has a login_hint to pass.
118	  if (email) await chrome.storage.local.set({ [EMAIL_KEY]: email });
119	  return { bundle, code: code || undefined };
120	}
121	
122	/** Durable email hint for silent renew (survives the restart that wipes the
123	 *  storage.session token bundle). */
124	async function readStoredEmail(): Promise<string | undefined> {
125	  const r = await chrome.storage.local.get(EMAIL_KEY);
126	  return (r[EMAIL_KEY] as string) ?? undefined;
127	}
128	
129	/** Valid tokens, silently re-minting if expired. Throws if interactive sign-in
130	 *  is required (caller surfaces a sign-in gate). */
131	export async function getValidTokens(): Promise<TokenBundle> {
132	  const cached = await readCache();
133	  if (cached && cached.expiresAt > Date.now()) return cached;
134	  // prompt=none silent renew, passing the account hint so it works on a
135	  // multi-account profile. cached?.email covers the common case; the durable copy
136	  // covers a post-restart renew where the session bundle is gone.
137	  const hint = cached?.email ?? (await readStoredEmail());
138	  try {
139	    return (await mint(false, hint)).bundle;
140	  } catch (err) {
