1	import { useEffect, useRef, useState } from 'react';
2	import { ChevronDown, Phone, User } from 'lucide-react';
3	import { Chip, Switch, TextField } from '@/design/components';
4	import type { DraftGuest } from '@/lib/types';
5	
6	type GuestEdit = {
7	  include?: boolean;
8	  name?: string;
9	  phone?: string;
10	};
11	
12	/** Two-letter monogram from a name ("Jane Doe" → "JD") or an email local-part
13	 *  ("jane.doe@x" → "JD"), so each guest has a stable, recognisable avatar. */
14	function monogram(seed: string): string {
15	  const parts = seed.trim().split(/[\s._-]+/).filter(Boolean);
16	  if (parts.length === 0) return '?';
17	  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
18	  return (parts[0][0] + parts[1][0]).toUpperCase();
19	}
20	
21	export function RosterRow({
22	  guest,
23	  onChange,
24	}: {
25	  guest: DraftGuest;
26	  onChange: (edit: GuestEdit) => void;
27	}) {
28	  const [name, setName] = useState(guest.name);
29	  const [phone, setPhone] = useState(guest.phone ?? '');
30	  // Details stay collapsed by default so each card is compact; the host opens
31	  // them only to make a correction. Sent guests are editable too — re-sending
32	  // pushes the change onto the already-issued pass.
33	  const [editing, setEditing] = useState(false);
34	
35	  // Reconcile server/background updates WITHOUT clobbering a live edit: adopt the
36	  // new server value only when the local field still equals the last server value
37	  // we saw (the host hasn't typed over it). So a background name/photo resolve fills
38	  // an untouched field, but a half-typed correction is never lost. (See the contacts
39	  // name-resolution flow — the name can change after first paint.)
40	  // Capture the PREVIOUS server value before mutating the ref: setName's functional
41	  // updater runs lazily (next commit), so reassigning the ref first would make the
42	  // updater compare against the new value and never adopt it. Snapshot prev, point
43	  // the ref at the new value, then compare the updater's local to that snapshot.
44	  const lastServerName = useRef(guest.name);
45	  useEffect(() => {
46	    const prev = lastServerName.current;
47	    lastServerName.current = guest.name;
48	    setName((local) => (local === prev ? guest.name : local));
49	  }, [guest.name]);
50	
51	  const lastServerPhone = useRef(guest.phone ?? '');
52	  useEffect(() => {
53	    const next = guest.phone ?? '';
54	    const prev = lastServerPhone.current;
55	    lastServerPhone.current = next;
56	    setPhone((local) => (local === prev ? next : local));
57	  }, [guest.phone]);
58	
59	  // Commit name/phone edits as the host TYPES (debounced), not only on blur, so the
60	  // Review button reflects the change right away and the edit is persisted sooner —
61	  // it can't be "lost" by a re-render before a blur ever fires (the reported bug).
62	  // Blur flushes any pending debounce immediately. onChange is idempotent per field,
63	  // so a flush after a debounce that already ran is a harmless no-op.
64	  const nameTimer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
65	  const phoneTimer = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
66	  useEffect(
67	    () => () => {
68	      clearTimeout(nameTimer.current);
69	      clearTimeout(phoneTimer.current);
70	    },
71	    [],
72	  );
73	  const commitName = (v: string) => {
74	    clearTimeout(nameTimer.current);
75	    nameTimer.current = setTimeout(() => {
76	      if (v !== guest.name) onChange({ name: v });
77	    }, 500);
78	  };
79	  const flushName = (v: string) => {
80	    clearTimeout(nameTimer.current);
81	    if (v !== guest.name) onChange({ name: v });
82	  };
83	  const commitPhone = (v: string) => {
84	    clearTimeout(phoneTimer.current);
85	    phoneTimer.current = setTimeout(() => {
86	      if (v !== (guest.phone ?? '')) onChange({ phone: v });
87	    }, 500);
88	  };
89	  const flushPhone = (v: string) => {
90	    clearTimeout(phoneTimer.current);
91	    if (v !== (guest.phone ?? '')) onChange({ phone: v });
92	  };
93	
94	  const sent = guest.status === 'sent';
95	  const cancelled = guest.status === 'cancelled';
96	  const display = guest.name || guest.email;
97	  // A sent guest toggled OFF is a pending cancel — re-sending will revoke their
98	  // pass (engine applyDraft cancels !include guests with an active pass), so we
99	  // dim the row and don't offer edits. Everyone we'd still issue/update a pass
100	  // for can be corrected, whether or not their pass already went out.
101	  const pendingCancel = sent && !guest.include;
102	  const editable = guest.include && !cancelled;
103	
104	  // The drawer handle names exactly what's still missing, so the host knows what
105	  // tapping it is for. A real name is absent when the engine flagged the name as the
106	  // email-derived fallback; phone is absent when blank.
107	  const hasName = !guest.nameIsFallback;
108	  const hasPhone = !!guest.phone?.trim();
109	  const drawerLabel = editing
110	    ? 'Hide details'
111	    : hasName && hasPhone
112	      ? 'Edit details'
113	      : !hasName && !hasPhone
114	        ? 'Add phone and name'
115	        : hasPhone
116	          ? 'Add name'
117	          : 'Add phone';
118	
119	  // Switch is no longer locked once a pass is sent: toggling off cancels on the
120	  // next update (mirrors the add-on), toggling back on re-issues.
121	  const switchLabel = sent
122	    ? guest.include
123	      ? `Cancel the pass for ${guest.email}`
124	      : `Re-issue a pass for ${guest.email}`
125	    : guest.include
126	      ? `Don’t invite ${guest.email}`
127	      : `Invite ${guest.email}`;
128	
129	  return (
130	    <div className={`guest${guest.include ? '' : ' guest--dim'}`}>
131	      <div className="guest__head">
132	        <span
133	          className={
134	            'guest__avatar' +
135	            (pendingCancel
136	              ? ' guest__avatar--dim'
137	              : sent
138	                ? ' guest__avatar--sent'
139	                : guest.include
140	                  ? ''
141	                  : ' guest__avatar--dim')
142	          }
143	          aria-hidden
144	        >
145	          {guest.photoUrl ? (
146	            <img className="guest__photo" src={guest.photoUrl} alt="" loading="lazy" />
147	          ) : (
148	            monogram(guest.name || guest.email.split('@')[0])
149	          )}
150	        </span>
151	
152	        <div className="guest__id">
153	          <div className="guest__name">
154	            <span className="type-label row__ellipsis">{display}</span>
155	            {guest.internal && !sent && !cancelled && <Chip>Internal</Chip>}
156	            {/* Check-in feedback (Tier 3 #6): once the guest has arrived, "Checked in"
157	                (or "Inside now") supersedes the plain "Pass sent" chip. */}
158	            {sent && guest.include && !guest.checkedIn && <Chip tone="success">Pass sent</Chip>}
159	            {guest.checkedIn && (
160	              <Chip tone="success">{guest.checkedInside ? 'Inside now' : 'Checked in'}</Chip>
161	            )}
162	            {pendingCancel && <Chip tone="error">Will cancel</Chip>}
163	            {cancelled && <Chip tone="error">Cancelled</Chip>}
164	          </div>
165	          <div className="type-label-sm text-muted row__ellipsis">{guest.email}</div>
166	        </div>
167	
168	        <Switch
169	          checked={guest.include}
170	          onChange={(v) => onChange({ include: v })}
171	          label={switchLabel}
172	        />
173	      </div>
174	
175	      {editable ? (
176	        // Full-bleed "scroll" drawer pinned to the card's bottom edge: a subtle,
177	        // edge-to-edge handle the host pulls open only when they need to correct
178	        // a detail — keeps each card compact by default.
179	        <div className={`guest__drawer${editing ? ' guest__drawer--open' : ''}`}>
180	          <button
181	            type="button"
182	            className="guest__handle"
183	            aria-expanded={editing}
184	            onClick={() => setEditing((v) => !v)}
185	          >
186	            <ChevronDown size={16} strokeWidth={2} className="guest__chev" />
187	            {drawerLabel}
188	          </button>
189	          {editing && (
190	            <div className="guest__form">
191	              <TextField
192	                label="Visitor name"
193	                value={name}
194	                leadingIcon={<User size={16} strokeWidth={2} />}
195	                onChange={(e) => {
196	                  setName(e.target.value);
197	                  commitName(e.target.value);
198	                }}
199	                onBlur={() => flushName(name)}
200	                placeholder="Full name"
201	              />
202	              <TextField
203	                label="Phone"
204	                value={phone}
205	                inputMode="tel"
206	                leadingIcon={<Phone size={16} strokeWidth={2} />}
207	                onChange={(e) => {
208	                  setPhone(e.target.value);
209	                  commitPhone(e.target.value);
210	                }}
211	                onBlur={() => flushPhone(phone)}
212	                placeholder="+91…"
213	              />
214	            </div>
215	          )}
216	        </div>
217	      ) : (
218	        !guest.include &&
219	        !cancelled && (
220	          <div className="guest__hint type-label-sm">Will not receive a pass. Toggle on to invite.</div>
221	        )
222	      )}
223	    </div>
224	  );
225	}
