116	   *  explicit "Cancel all passes" AND by the background safety net when a deleted
117	   *  event would otherwise leave live passes (no server-side OAuth watch). Idempotent
118	   *  on the engine — already-cancelled passes are skipped (no double notice). */
119	  cancelEvent: (idToken: string, iCalUid: string) =>
120	    call<{ iCalUid: string; cancelled: number; activeCount: number }>(
121	      'cancel-event',
122	      'POST',
123	      idToken,
124	      { iCalUid },
125	    ),
