109	
110	/* ---------- Button ---------- */
111	.btn {
112	  display: inline-flex;
113	  align-items: center;
114	  justify-content: center;
115	  gap: var(--space-sm);
116	  border: none;
117	  border-radius: var(--radius-pill);
118	  padding: 10px 20px;
119	  font: inherit;
120	  font-weight: 600;
121	  letter-spacing: 0.1px;
122	  cursor: pointer;
123	  position: relative;
124	  overflow: hidden;
125	  transition: box-shadow var(--motion-fast) var(--motion-easing),
126	    background-color var(--motion-fast) var(--motion-easing),
127	    opacity var(--motion-fast) var(--motion-easing);
128	  user-select: none;
129	}
130	.btn:disabled { opacity: 0.5; cursor: default; pointer-events: none; }
131	.btn::after {
132	  content: '';
133	  position: absolute;
134	  inset: 0;
135	  background: currentColor;
136	  opacity: 0;
137	  transition: opacity var(--motion-fast) var(--motion-easing);
138	}
139	.btn:hover::after { opacity: var(--state-hover); }
140	.btn:active::after { opacity: var(--state-pressed); }
141	
142	.btn--filled { background: var(--color-primary); color: var(--color-on-primary); }
143	.btn--filled:hover { box-shadow: var(--elev-1); }
144	.btn--tonal { background: var(--color-primary-container); color: var(--color-on-primary-container); }
145	.btn--text { background: transparent; color: var(--color-primary); padding: 10px 12px; }
146	.btn--danger { background: var(--color-error); color: var(--color-on-error); }
147	.btn--block { display: flex; width: 100%; }
