/* Design system for the side panel document. CSS custom properties mirror
   design/tokens.ts. Component classes below are intentionally small wrappers
   over Material 3 values — no UI framework. */

:root {
  /* color roles */
  --color-primary: #92288e;
  --color-on-primary: #ffffff;
  --color-primary-container: #f8d9f5;
  --color-on-primary-container: #310031;

  --color-error: #ba1a1a;
  --color-on-error: #ffffff;
  --color-error-container: #ffdad6;
  --color-on-error-container: #410002;

  --color-success: #3f6212;
  --color-success-container: #dcf2bc;
  --color-on-success-container: #142000;

  --color-background: #fbf7fa;
  --color-on-background: #1e1a1d;
  --color-surface: #fbf7fa;
  --color-on-surface: #1e1a1d;

  --color-surface-lowest: #ffffff;
  --color-surface-low: #f5eff3;
  --color-surface-container: #efe8ee;
  --color-surface-high: #e9e2e8;
  --color-surface-highest: #e3dde2;

  --color-on-surface-variant: #4d444b;
  --color-outline: #7c747a;
  --color-outline-variant: #cdc4cb;
  --color-scrim: rgba(0, 0, 0, 0.45);

  /* state layer opacities (MD3) */
  --state-hover: 0.08;
  --state-focus: 0.12;
  --state-pressed: 0.12;

  /* spacing */
  --space-xxs: 2px;
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 12px;
  --space-lg: 16px;
  --space-xl: 24px;
  --space-xxl: 32px;

  /* shape */
  --radius-xs: 4px;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 24px;
  --radius-pill: 999px;

  /* motion */
  --motion-fast: 120ms;
  --motion-base: 200ms;
  --motion-slow: 320ms;
  --motion-easing: cubic-bezier(0.2, 0, 0, 1);
  --motion-emphasized: cubic-bezier(0.3, 0, 0, 1);

  /* elevation */
  --elev-1: 0 1px 2px rgba(0, 0, 0, 0.08);
  --elev-2: 0 2px 6px rgba(0, 0, 0, 0.1);
  --elev-3: 0 4px 12px rgba(0, 0, 0, 0.12);
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  height: 100%;
}

body {
  margin: 0;
  background: var(--color-background);
  color: var(--color-on-background);
  font-family: 'Google Sans', 'Roboto', system-ui, -apple-system, sans-serif;
  font-size: 14px;
  line-height: 20px;
  -webkit-font-smoothing: antialiased;
}

/* typography helpers */
.type-headline { font-size: 24px; line-height: 32px; font-weight: 700; }
.type-title-lg { font-size: 22px; line-height: 28px; font-weight: 600; }
.type-title { font-size: 16px; line-height: 24px; font-weight: 600; letter-spacing: 0.15px; }
.type-body-lg { font-size: 15px; line-height: 22px; }
.type-body { font-size: 14px; line-height: 20px; letter-spacing: 0.25px; }
.type-label { font-size: 14px; line-height: 20px; font-weight: 600; letter-spacing: 0.1px; }
.type-label-sm { font-size: 12px; line-height: 16px; font-weight: 600; letter-spacing: 0.5px; }
.text-muted { color: var(--color-on-surface-variant); }

/* scrollbar — slim, unobtrusive */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-thumb {
  background: var(--color-outline-variant);
  border-radius: var(--radius-pill);
}
::-webkit-scrollbar-track { background: transparent; }

/* ---------- Button ---------- */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-sm);
  border: none;
  border-radius: var(--radius-pill);
  padding: 10px 20px;
  font: inherit;
  font-weight: 600;
  letter-spacing: 0.1px;
  cursor: pointer;
  position: relative;
  overflow: hidden;
  transition: box-shadow var(--motion-fast) var(--motion-easing),
    background-color var(--motion-fast) var(--motion-easing),
    opacity var(--motion-fast) var(--motion-easing);
  user-select: none;
}
.btn:disabled { opacity: 0.5; cursor: default; pointer-events: none; }
.btn::after {
  content: '';
  position: absolute;
  inset: 0;
  background: currentColor;
  opacity: 0;
  transition: opacity var(--motion-fast) var(--motion-easing);
}
.btn:hover::after { opacity: var(--state-hover); }
.btn:active::after { opacity: var(--state-pressed); }

.btn--filled { background: var(--color-primary); color: var(--color-on-primary); }
.btn--filled:hover { box-shadow: var(--elev-1); }
.btn--tonal { background: var(--color-primary-container); color: var(--color-on-primary-container); }
.btn--text { background: transparent; color: var(--color-primary); padding: 10px 12px; }
.btn--danger { background: var(--color-error); color: var(--color-on-error); }
.btn--block { display: flex; width: 100%; }

/* ---------- Card ---------- */
.card {
  background: var(--color-surface-lowest);
  border: 1px solid var(--color-outline-variant);
  border-radius: var(--radius-lg);
  padding: var(--space-lg);
}

/* ---------- Skeleton ---------- */
.skeleton {
  background: linear-gradient(
    90deg,
    var(--color-surface-high) 25%,
    var(--color-surface-highest) 37%,
    var(--color-surface-high) 63%
  );
  background-size: 400% 100%;
  border-radius: var(--radius-sm);
  animation: skeleton-shimmer 1.4s ease infinite;
}
@keyframes skeleton-shimmer {
  0% { background-position: 100% 50%; }
  100% { background-position: 0 50%; }
}

/* ---------- Spinner ---------- */
.spinner {
  display: inline-block;
  width: 16px;
  height: 16px;
  border: 2px solid currentColor;
  border-right-color: transparent;
  border-radius: 50%;
  animation: spinner-rotate 0.7s linear infinite;
}
@keyframes spinner-rotate { to { transform: rotate(360deg); } }

/* ---------- Switch (MD3) ---------- */
.switch {
  position: relative;
  display: inline-flex;
  flex: 0 0 auto;
  width: 44px;
  height: 24px;
  border-radius: var(--radius-pill);
  border: 2px solid var(--color-outline);
  background: var(--color-surface-highest);
  cursor: pointer;
  transition: background-color var(--motion-base) var(--motion-easing),
    border-color var(--motion-base) var(--motion-easing);
  padding: 0;
}
.switch__thumb {
  position: absolute;
  top: 50%;
  left: 4px;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--color-outline);
  transform: translate(0, -50%);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: var(--color-primary);
  transition: transform var(--motion-base) var(--motion-emphasized),
    width var(--motion-base) var(--motion-emphasized),
    height var(--motion-base) var(--motion-emphasized),
    background-color var(--motion-base) var(--motion-easing);
}
.switch__check {
  opacity: 0;
  transition: opacity var(--motion-fast) var(--motion-easing);
}
.switch[aria-checked='true'] {
  background: var(--color-primary);
  border-color: var(--color-primary);
}
.switch[aria-checked='true'] .switch__thumb {
  width: 16px;
  height: 16px;
  background: var(--color-on-primary);
  transform: translate(18px, -50%);
}
.switch[aria-checked='true'] .switch__check { opacity: 1; }
.switch:disabled { opacity: 0.5; cursor: default; }

/* ---------- Text field (filled, slim) ---------- */
.field { display: flex; flex-direction: column; gap: var(--space-xxs); }
.field__label {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.4px;
  color: var(--color-on-surface-variant);
}
.field__input {
  font: inherit;
  color: var(--color-on-surface);
  background: var(--color-surface-low);
  border: 1px solid var(--color-outline-variant);
  border-radius: var(--radius-sm);
  padding: 8px 10px;
  outline: none;
  transition: border-color var(--motion-fast) var(--motion-easing),
    box-shadow var(--motion-fast) var(--motion-easing);
}
.field__input:focus {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 1px var(--color-primary);
}
.field__input::placeholder { color: var(--color-outline); }
select.field__input { cursor: pointer; appearance: none; }

/* leading-icon variant */
.field__wrap { position: relative; display: flex; align-items: center; }
.field__icon {
  position: absolute;
  left: 10px;
  display: inline-flex;
  color: var(--color-on-surface-variant);
  pointer-events: none;
}
.field__input--with-icon { width: 100%; padding-left: 34px; }
/* keep the icon in step with focus colour */
.field__wrap:focus-within .field__icon { color: var(--color-primary); }

/* ---------- Icon button ---------- */
.icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border: none;
  border-radius: 50%;
  background: transparent;
  color: var(--color-on-surface-variant);
  cursor: pointer;
  position: relative;
  overflow: hidden;
  transition: color var(--motion-fast) var(--motion-easing);
}
.icon-btn::after {
  content: '';
  position: absolute;
  inset: 0;
  background: currentColor;
  opacity: 0;
  transition: opacity var(--motion-fast) var(--motion-easing);
}
.icon-btn:hover::after { opacity: var(--state-hover); }
.icon-btn:active::after { opacity: var(--state-pressed); }
.icon-btn:disabled { opacity: 0.4; pointer-events: none; }

/* ---------- Chip ---------- */
.chip {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  height: 22px;
  padding: 0 8px;
  border-radius: var(--radius-sm);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.3px;
}
.chip--neutral { background: var(--color-surface-high); color: var(--color-on-surface-variant); }
.chip--success { background: var(--color-success-container); color: var(--color-on-success-container); }
.chip--error { background: var(--color-error-container); color: var(--color-on-error-container); }

/* ---------- List row ---------- */
.row {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  padding: var(--space-md) 0;
}
.row + .row { border-top: 1px solid var(--color-outline-variant); }
.row--dim { opacity: 0.55; }
.row__grow { flex: 1 1 auto; min-width: 0; }
.row__ellipsis {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ---------- Guest (roster) card ----------
   Each guest is its own self-contained card, separated by a gap from the next —
   so a host scans the roster as distinct people, not rows blurring together.
   overflow:hidden clips the detail drawer's full-bleed tint to the rounded
   corners. */
.roster {
  display: grid;
  gap: var(--space-md);
}
.guest {
  background: var(--color-surface-lowest);
  border: 1px solid var(--color-outline-variant);
  border-radius: var(--radius-lg);
  overflow: hidden;
  padding: var(--space-md) var(--space-lg);
  transition: opacity var(--motion-base) var(--motion-easing),
    box-shadow var(--motion-fast) var(--motion-easing);
}
.guest--dim { opacity: 0.6; }

.guest__head {
  display: flex;
  align-items: center;
  gap: var(--space-md);
}

.guest__avatar {
  flex: 0 0 auto;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.3px;
  background: var(--color-primary-container);
  color: var(--color-on-primary-container);
  user-select: none;
  transition: background-color var(--motion-base) var(--motion-easing),
    color var(--motion-base) var(--motion-easing);
}
.guest__avatar--sent { background: var(--color-success-container); color: var(--color-on-success-container); }
.guest__avatar--dim { background: var(--color-surface-high); color: var(--color-on-surface-variant); }
/* Resolved profile photo fills the avatar circle; falls back to the monogram. */
.guest__photo { width: 100%; height: 100%; border-radius: 50%; object-fit: cover; display: block; }

.guest__id { flex: 1 1 auto; min-width: 0; }
/* Name shrinks + ellipsizes; status chips ("Pass sent" / "Will cancel") never
   shrink, so a long name/email can't squash or wrap the pill. */
.guest__name { display: flex; align-items: center; gap: var(--space-xs); min-width: 0; }
.guest__name .row__ellipsis { flex: 0 1 auto; min-width: 0; }
.guest__name .chip { flex: 0 0 auto; }

.guest__hint {
  margin: var(--space-xs) 0 0 calc(36px + var(--space-md));
  color: var(--color-on-surface-variant);
  font-weight: 500;
}
@keyframes guest-expand {
  from { opacity: 0; transform: translateY(-4px); }
  to { opacity: 1; transform: none; }
}

/* ---- Guest detail "scroll" drawer ----
   Full-bleed expandable footer pulled from the card's bottom edge: the negative
   side margins cancel the roster Card's horizontal padding so the tint runs edge
   to edge; the negative bottom cancels the guest row's bottom padding so it sits
   flush. The roster Card sets overflow:hidden, so the tint is clipped to its
   rounded corners. Collapsed by default → cards stay compact. */
.guest__drawer {
  margin: var(--space-sm) calc(-1 * var(--space-lg)) calc(-1 * var(--space-md));
  background: var(--color-surface-low);
  border-top: 1px solid var(--color-outline-variant);
}
.guest__handle {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  width: 100%;
  border: none;
  background: none;
  cursor: pointer;
  font: inherit;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.2px;
  color: var(--color-primary);
  padding: 10px var(--space-lg);
  transition: background-color var(--motion-base) var(--motion-easing);
}
.guest__handle:hover { background: var(--color-surface-high); }
.guest__chev { transition: transform var(--motion-base) var(--motion-easing); }
.guest__drawer--open .guest__chev { transform: rotate(180deg); }

/* The inputs unroll inside the drawer, padded to the card edges. */
.guest__form {
  display: grid;
  gap: var(--space-sm);
  padding: var(--space-xs) var(--space-lg) var(--space-md);
  animation: guest-expand var(--motion-base) var(--motion-easing) both;
}

/* ---------- Banner (Phase 2 / inline messages) ---------- */
.banner {
  display: flex;
  align-items: flex-start;
  gap: var(--space-sm);
  padding: var(--space-md);
  border-radius: var(--radius-md);
}
.banner--error { background: var(--color-error-container); color: var(--color-on-error-container); }
.banner--info { background: var(--color-primary-container); color: var(--color-on-primary-container); }

/* keyboard focus ring (focus-visible only — no ring on mouse) */
:where(button, a, input, select, [tabindex]):focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}
.field__input:focus-visible {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 2px var(--color-primary);
}
.switch:focus-visible { outline-offset: 3px; }

/* fade/slide-in for panel content */
.enter {
  animation: enter var(--motion-base) var(--motion-easing) both;
}
@keyframes enter {
  from { opacity: 0; transform: translateY(6px); }
  to { opacity: 1; transform: none; }
}

/* honor user preference */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

